token := jwt.NewWithClaims(jwt.SigningMethodHS256, JTWPortalTokenClaims{
  Namespace: input.Namespace,
  Id:        uuid.New().String(),
  RegisteredClaims: jwt.RegisteredClaims{
    Subject:   input.Subject,
    ExpiresAt: jwt.NewNumericDate(expiresAt),
    IssuedAt:  jwt.NewNumericDate(time.Now()),
    Issuer:    PortalTokenIssuer,
  },
  AllowedMeterSlugs: *allowedMeterSlugs,
})
tokenString, err := token.SignedString(a.secret)

claims, err := a.portal.Validate(r.Context(), bearerToken)
if err != nil { return r, fmt.Errorf("invalid token: %w", err) }
if claims.Subject == "" { return r, errors.New("invalid subject") }
if len(claims.AllowedMeterSlugs) != 0 && !slices.Contains(claims.AllowedMeterSlugs, meterSlug) {
  return r, errors.New("meter slug not allowed")
}
r = r.WithContext(context.WithValue(r.Context(), AuthenticatorSubjectSessionKey, claims.Subject))

meterList, err := h.meterService.ListMeters(ctx, meter.ListMetersParams{
  Namespace: request.Namespace,
  Key:       &filter.FilterString{In: request.AllowedMeterSlugs},
})
metersBySlug := lo.KeyBy(meterList.Items, func(m meter.Meter) string { return m.Key })
for _, slug := range *request.AllowedMeterSlugs {
  if _, ok := metersBySlug[slug]; !ok { return nil, meter.NewMeterNotFoundError(slug) }
}
token, err := h.portalService.CreateToken(ctx, request)
portalToken := toAPIPortalToken(token)
portalToken.Token = token.Token
